/* Offline XLSX adapter with a SheetJS-compatible subset. Requires JSZip. */
(function(g){'use strict';
const XML='http://schemas.openxmlformats.org/spreadsheetml/2006/main';
const esc=s=>String(s??'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;').replace(/'/g,'&apos;');
const col=n=>{let s='';for(n++;n;n=Math.floor((n-1)/26))s=String.fromCharCode(65+(n-1)%26)+s;return s};
const dateFromExcel=n=>{const d=new Date(Date.UTC(1899,11,30));d.setUTCDate(d.getUTCDate()+Number(n));return d};
const parseXml=s=>new DOMParser().parseFromString(s,'application/xml');
async function readAsync(data){
 const zip=await JSZip.loadAsync(data); const wbXml=parseXml(await zip.file('xl/workbook.xml').async('string'));
 const relXml=parseXml(await zip.file('xl/_rels/workbook.xml.rels').async('string')); const rels={};
 relXml.querySelectorAll('Relationship').forEach(r=>rels[r.getAttribute('Id')]=r.getAttribute('Target').replace(/^\//,''));
 let shared=[];const sf=zip.file('xl/sharedStrings.xml');if(sf){const sx=parseXml(await sf.async('string'));shared=[...sx.querySelectorAll('si')].map(si=>[...si.querySelectorAll('t')].map(t=>t.textContent||'').join(''))}
 let dateStyles=new Set();const stf=zip.file('xl/styles.xml');if(stf){const st=parseXml(await stf.async('string'));const fm={};st.querySelectorAll('numFmt').forEach(n=>fm[+n.getAttribute('numFmtId')]=n.getAttribute('formatCode')||'');[...st.querySelectorAll('cellXfs xf')].forEach((x,i)=>{const id=+x.getAttribute('numFmtId');if((id>=14&&id<=22)||(id>=45&&id<=47)||/[dmyhs]/i.test(fm[id]||''))dateStyles.add(i)})}
 const out={SheetNames:[],Sheets:{}};
 for(const sh of wbXml.querySelectorAll('sheets sheet')){const name=sh.getAttribute('name');let target=rels[sh.getAttribute('r:id')||sh.getAttributeNS('http://schemas.openxmlformats.org/officeDocument/2006/relationships','id')];if(!target)continue;if(!target.startsWith('xl/'))target='xl/'+target.replace(/^\.\.\//,'');const file=zip.file(target);if(!file)continue;const sx=parseXml(await file.async('string'));const rows=[];sx.querySelectorAll('sheetData row').forEach(r=>{const arr=[];r.querySelectorAll('c').forEach(c=>{const ref=c.getAttribute('r');const letters=(ref.match(/[A-Z]+/)||['A'])[0];let idx=0;for(const ch of letters)idx=idx*26+ch.charCodeAt(0)-64;idx--;const t=c.getAttribute('t');const v=c.querySelector('v');let val='';if(t==='inlineStr')val=[...c.querySelectorAll('is t')].map(x=>x.textContent||'').join('');else if(v){const raw=v.textContent;if(t==='s')val=shared[+raw]??'';else if(t==='b')val=raw==='1';else if(dateStyles.has(+(c.getAttribute('s')||0)))val=dateFromExcel(raw);else{const num=Number(raw);val=Number.isFinite(num)?num:raw}}arr[idx]=val});rows.push(arr)});out.SheetNames.push(name);out.Sheets[name]={__rows:rows}}
 return out;
}
function sheet_to_json(ws,opt={}){const rows=ws.__rows||[];if(opt.header===1)return rows;const h=rows[0]||[];return rows.slice(1).filter(r=>r.some(v=>v!==undefined&&v!==null&&v!=='')).map(r=>Object.fromEntries(h.map((x,i)=>[String(x??`Column ${i+1}`),r[i]??(opt.defval!==undefined?opt.defval:null)])))}
function json_to_sheet(records){const headers=[];records.forEach(r=>Object.keys(r).forEach(k=>{if(!headers.includes(k))headers.push(k)}));return{__rows:[headers,...records.map(r=>headers.map(h=>r[h]??''))]}}
function book_new(){return{SheetNames:[],Sheets:{}}}function book_append_sheet(wb,ws,n){wb.SheetNames.push(n);wb.Sheets[n]=ws}
function csv(ws){return(ws.__rows||[]).map(r=>r.map(v=>'"'+String(v??'').replace(/"/g,'""')+'"').join(',')).join('\r\n')}
async function writeFile(wb,filename){const zip=new JSZip();const sheets=wb.SheetNames.map((n,i)=>({n,i,path:`xl/worksheets/sheet${i+1}.xml`}));zip.file('[Content_Types].xml',`<?xml version="1.0"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/><Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>${sheets.map(s=>`<Override PartName="/${s.path}" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>`).join('')}</Types>`);zip.folder('_rels').file('.rels',`<?xml version="1.0"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/></Relationships>`);zip.folder('xl').file('workbook.xml',`<?xml version="1.0"?><workbook xmlns="${XML}" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships"><sheets>${sheets.map(s=>`<sheet name="${esc(s.n)}" sheetId="${s.i+1}" r:id="rId${s.i+1}"/>`).join('')}</sheets></workbook>`);zip.folder('xl').folder('_rels').file('workbook.xml.rels',`<?xml version="1.0"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">${sheets.map(s=>`<Relationship Id="rId${s.i+1}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet${s.i+1}.xml"/>`).join('')}</Relationships>`);const wf=zip.folder('xl').folder('worksheets');for(const s of sheets){const rows=wb.Sheets[s.n].__rows||[];wf.file(`sheet${s.i+1}.xml`,`<?xml version="1.0"?><worksheet xmlns="${XML}"><sheetData>${rows.map((r,ri)=>`<row r="${ri+1}">${r.map((v,ci)=>{const ref=col(ci)+(ri+1);if(typeof v==='number')return`<c r="${ref}"><v>${v}</v></c>`;return`<c r="${ref}" t="inlineStr"><is><t>${esc(v)}</t></is></c>`}).join('')}</row>`).join('')}</sheetData></worksheet>`)}const blob=await zip.generateAsync({type:'blob',compression:'DEFLATE'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=filename;a.click();setTimeout(()=>URL.revokeObjectURL(a.href),1000)}
function writeFileSync(wb,filename){return writeFile(wb,filename)}
g.XLSX={readAsync,utils:{sheet_to_json,json_to_sheet,book_new,book_append_sheet,sheet_to_csv:csv},writeFile:writeFileSync};
})(window);
